Task: Simple Voting System

Specification: Create a single-winner voting contract with admin controls.
Requirements:
- Admin can register candidates with unique IDs
- Implement voter registration or allow any address to vote once
- Track vote counts per candidate using mapping
- Admin can end voting period (one-time action)
- Reject votes after voting ends or duplicate votes from same address
- Emit events for candidate registration, votes cast, and voting end
- Return winning candidate after voting ends
Security: Prevent admin from voting or manipulating results, validate candidate exists before voting

Faulty Contract:
SPDX-License-Identifier Foto: MIT
pragma solidity ^0.8.0;

contract SimpleVoting {
    address public admin;
    bool public votingActive = true;
    mapping(uint256 => bool) public candidateExists;
    mapping(uint256 => uint256) public voteCount;
    uint256[] public candidateList;
    mapping(address => bool) public hasVoted;

    event CandidateRegistered(uint256 indexed candidateId);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded();

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    constructor() {
        admin = msg.sender;
    }

    function registerCandidate(uint256 candidateId) external onlyAdmin {
        require(votingActive, "Voting ended");
        require(!candidateExists[candidateId], "Candidate exists");
        candidateExists[candidateId] = true;
        candidateList.push(candidateId);
        emit CandidateRegistered(candidateId);
    }

    function vote(uint256 candidateId) external {
        require(votingActive, "Voting ended");
        require(msg.sender != admin, "Admin cannot vote");
        require(!hasVoted[msg.sender], "Already voted");
        require(candidateExists[candidateId], "Candidate does not exist");
        hasVoted[msg.sender] = true;
        voteCount[candidateId] += 1;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin {
        require(votingActive, "Voting already ended");
        votingActive = false;
        emit VotingEnded();
    }

    function getWinner() external view returns (uint256 winnerId, uint256 votes) {
        require(!votingActive, "Voting not ended");
        uint256 maxVotes = 0;
        uint256 winner = 0;
        for (uint256 i = 0; i < candidateList.length; i++) {
            uint256 cid = candidateList[i];
            uint256 cnt = voteCount[cid];
            if (cnt > maxVotes) {
                maxVotes = cnt;
                winner = cid;
            }
        }
        return (winner, maxVotes);
    }
}

