Task: Escrow Contract

Specification: Create a three-party escrow contract with dispute resolution.
Requirements:
- Initialize with buyer, seller, and arbiter addresses at deployment
- Buyer deposits exact Ether amount during contract creation (payable constructor)
- Seller can mark item as delivered
- Buyer can release payment to seller if satisfied
- Arbiter can resolve disputes and allocate funds to buyer or seller
- Track contract state (Created, Delivered, Released, Refunded, Disputed)
- Emit events for all state changes
- Ensure funds can only be released once using state checks
Security: Use Checks-Effects-Interactions pattern, prevent reentrancy, validate all addresses are unique and non-zero

Faulty Contract:
pragma solidity ^0.8.0;

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }
    State public state;

    address public immutable buyer;
    address public immutable seller;
    address public immutable arbiter;

    bool private locked;

    event EscrowCreated(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event Delivered();
    event Released();
    event Refunded();
    event Disputed();
    event Resolved(address indexed recipient, uint256 amount);

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Only buyer");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Only seller");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Only arbiter");
        _;
    }

    modifier inState(State _state) {
        require(state == _state, "Invalid state");
        _;
    }

    modifier nonReentrant() {
        require(!locked, "ReentrancyGuard: reentrant call");
        locked = true;
        _;
        locked = false;
    }

    constructor(address _buyer, address _seller, address _arbiter) payable {
        require(msg.sender == _buyer, "Buyer must deploy");
        require(_buyer != address(0) && _seller != address(0) && _arbiter != address(0), "Zero address");
        require(_buyer != _seller && _buyer != _arbiter && _seller != _arbiter, "Addresses must be unique");
        require(msg.value > 0, "Deposit required");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        state = State.Created;

        emit EscrowCreated(buyer, seller, arbiter, msg.value);
    }

    function deliver() external onlySeller inState(State.Created) {
        state = State.Delivered;
        emit Delivered();
    }

    function release() external onlyBuyer inState(State.Delivered) nonReentrant {
        state = State.Released;
        uint256 amount = address(this).balance;
        (bool success, ) = seller.call{value: amount}("");
        require(success, "Transfer failed");
        emit Released();
    }

    function dispute() external (onlyBuyer or onlySeller) inState(State.Delivered) {
        state = State.Disputed;
        emit Disputed();
    }

    function resolve(bool toSeller) external onlyArbiter inState(State.Disputed) nonReentrant {
        address recipient = toSeller ? seller : buyer;
        state = toSeller ? State.Released : State.Refunded;
        uint256 amount = address(this).balance;
        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Transfer failed");
        emit Resolved(recipient, amount);
    }
}

