Task: Multi-Signature Wallet

Specification: Create a multi-signature wallet requiring multiple approvals.
Requirements:
- Initialize with array of owner addresses and required approval threshold
- Validate threshold <= number of owners and > 0
- Implement transaction proposal (target address, value, data)
- Track approvals per transaction using nested mappings
- Allow owners to approve transactions
- Execute transaction only when threshold met
- Prevent double-approvals from same owner
- Emit events for submissions, approvals, and executions
Security: Use call instead of transfer for execution, handle failed transactions, prevent reentrancy on execution

Faulty Contract:
pragma solidity ^0.8.20;

contract MultiSigWallet {
    uint256 public threshold;
    address[] public owners;
    mapping(address => bool) public isOwner;
    mapping(uint256 => Transaction) public transactions;
    mapping(uint256 => mapping(address => bool)) public approvals;

    struct Transaction {
        address to;
        uint256 value;
        bytes data;
        bool executed;
        uint256 approvalsCount;
    }

    event Submission(uint256 indexed txId, address indexed proposer, address indexed to, uint256 value, bytes data);
    event Approval(uint256 indexed txId, address indexed owner);
    event Execution(uint256 indexed txId, address indexed executor);
    event ExecutionFailed(uint256 indexed txId, address indexed executor, bytes reason);

    modifier onlyOwner() {
        require(isOwner[msg.sender], "Not owner");
        _;
    }

    modifier nonReentrant() {
        require(!locked, "ReentrancyGuard: reentrant call");
        locked = true;
        _;
        locked = false;
    }

    bool private locked;

    constructor(address[] memory _owners, uint256 _threshold) {
        require(_owners.length > 0, "Owners required");
        require(_threshold > 0 && _threshold <= _owners.length, "Invalid threshold");
        for (uint256 i = 0; i < _owners.length; i++) {
            address owner = _owners[i];
            require(owner != address(0), "Zero address");
            require(!isOwner[owner], "Duplicate owner");
