/**
 * @title HighestBidAuction
 * @notice A simple highest‑bid auction with automatic refunds and pull‑payment safety.
 */
contract HighestBidAuction {
    /* -------------------------------------------------------------------------- */
    /*                                 EVENTS & ERRORS                              */
    /* -------------------------------------------------------------------------- */

    event NewBid(address indexed bidder, uint256 amount);
    event AuctionEnded(address indexed winner, uint256 amount);
    event Withdrawn(address indexed to, uint256 amount);

    /* -------------------------------------------------------------------------- */
    /*                                 STATE VARIABLES                             */
    /* -------------------------------------------------------------------------- */

    address public immutable owner;
    uint256 public immutable startTime;
    uint256 public immutable endTime;
    uint256 public immutable minBid;

    address public highestBidder;
    uint256 public highestBid;

    bool public ended;

    // Pull‑payment mapping for outbid refunds
    mapping(address => uint256) public pendingReturns;

    /* -------------------------------------------------------------------------- */
    /*                                 MODIFIERS                                  */
    /* -------------------------------------------------------------------------- */

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyDuringAuction() {
        require(block.timestamp >= startTime && block.timestamp <= endTime, "Auction not active");
        _;
    }

    modifier onlyAfterAuction() {
        require(block.timestamp > endTime, "Auction not ended");
        _;
    }

    /* -------------------------------------------------------------------------- */
    /*                                 CONSTRUCTOR                                */
    /* -------------------------------------------------------------------------- */

    /**
     * @dev Deploys the auction contract.
     * @param _startTime Unix timestamp when the auction starts.
     * @param _endTime   Unix timestamp when the auction ends.
     * @param _minBid    Minimum acceptable bid.
     */
    constructor(uint256 _startTime, uint256 _endTime, uint256 _minBid) {
        require(_startTime < _endTime, "Invalid time range");
        require(_minBid > 0, "Minimum bid must be > 0");

        owner = msg.sender;
        startTime = _startTime;
        endTime = _endTime;
        minBid = _minBid;
    }

    /* -------------------------------------------------------------------------- */
    /*                                 BIDDING                                    */
    /* -------------------------------------------------------------------------- */

    /**
     * @notice Places a bid. Must be higher than the current highest bid
     *         and at least the minimum bid. Previous highest bidder is
     *         refunded via pull‑payment.
     */
    function bid() external payable onlyDuringAuction {
        require(msg.value >= minBid, "Bid below minimum");
        require(msg.value > highestBid, "Bid not high enough");

        // Refund previous highest bidder
        if (highestBidder != address(0)) {
            pendingReturns[highestBidder] += highestBid;
        }

        highestBid = msg.value;
        highestBidder = msg.sender;

        emit NewBid(msg.sender, msg.value);
    }

    /* -------------------------------------------------------------------------- */
    /*                                 WITHDRAWALS                                */
    /* -------------------------------------------------------------------------- */

    /**
     * @notice Withdraws any pending refund for the caller.
     */
    function withdraw() external {
        uint256 amount = pendingReturns[msg.sender];
        require(amount > 0, "No funds to withdraw");

        // Zero out before transfer to prevent re‑entrancy
        pendingReturns[msg.sender] = 0;

        (bool ok, ) = msg.sender.call{value: amount}("");
        require(ok, "Transfer failed");

        emit Withdrawn(msg.sender, amount);
    }

    /**
     * @notice Ends the auction. Can only be called by the owner after the
     *         auction period has elapsed.
     */
    function endAuction() external onlyOwner onlyAfterAuction {
        require(!ended, "Auction already ended");
        ended = true;

        emit AuctionEnded(highestBidder, highestBid);
    }

    /**
     * @notice Allows the auction creator to withdraw the winning bid after
     *         the auction has ended.
     */
    function withdrawWinningBid() external onlyOwner onlyAfterAuction {
        require(ended, "Auction not ended");
        require(highestBid > 0, "No winning bid");

        uint256 amount = highestBid;
        highestBid = 0; // Prevent re‑entrancy

        (bool ok, ) = owner.call{value: amount}("");
        require(ok, "Transfer failed");

        emit Withdrawn(owner, amount);
    }

    /* -------------------------------------------------------------------------- */
    /*                                 FALLBACK & RECEIVE                         */
    /* -------------------------------------------------------------------------- */

    // Reject any direct ether transfers
    receive() external payable {
        revert("Use bid() to place a bid");
    }

    fallback() external payable {
        revert("Use bid() to place a bid");
    }
}

