// SPDX-License-Identifier: MIT
pragma solidity ^0.8.x;

contract SimpleVoting {
    enum VotingStatus { NotStarted, InProgress, Ended }

    address public admin;
    mapping(uint256 => string) public candidates;
    mapping(address => bool) public voters;
    mapping(uint256 => uint256) public voteCounts;
    uint256 public winnerCandidateId;
    VotingStatus public votingStatus;

    event CandidateRegistered(uint256 candidateId, string name);
    event VoteCast(address voter, uint256 candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingStatus = VotingStatus.NotStarted;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can call this function");
        _;
    }

    modifier votingInProgress() {
        require(votingStatus == VotingStatus.InProgress, "Voting is not in progress");
        _;
    }

    modifier votingNotEnded() {
        require(votingStatus != VotingStatus.Ended, "Voting has ended");
        _;
    }

    function registerCandidate(uint256 candidateId, string memory name) external onlyAdmin votingNotEnded {
        require(candidates[candidateId] == "", "Candidate ID already exists");
        candidates[candidateId] = name;
        emit CandidateRegistered(candidateId, name);
    }

    function startVoting() external onlyAdmin {
        require(votingStatus == VotingStatus.NotStarted, "Voting has already started or ended");
        votingStatus = VotingStatus.InProgress;
    }

    function endVoting() external onlyAdmin {
        require(votingStatus == VotingStatus.InProgress, "Voting is not in progress");
        votingStatus = VotingStatus.Ended;
        emit VotingEnded();
    }

    function vote(uint256 candidateId) external votingInProgress votingNotEnded {
        require(candidates[candidateId] != "", "Candidate does not exist");
        require(!voters[msg.sender], "Already voted");

        voters[msg.sender] = true;
        voteCounts[candidateId]++;
        emit VoteCast(msg.sender, candidateId);
    }

    function getWinner() external view returns (uint256) {
        require(votingStatus == VotingStatus.Ended, "Voting has not ended");
        uint256 maxVotes = 0;
        for (uint256 i = 0; i < candidates.length; i++) {
            if (voteCounts[i] > maxVotes) {
                maxVotes = voteCounts[i];
                winnerCandidateId = i;
            }
        }
        return winnerCandidateId;
    }

    function getVoteCount(uint256 candidateId) external view returns (uint256) {
        return voteCounts[candidateId];
    }

    receive() external payable {}
}

