    );

    event ApproveTransaction(
        uint256 indexed id,
        address indexed owner,
        bool approved
    );

    event ExecuteTransaction(
        uint256 indexed id,
        address indexed owner
    );

    constructor(address[] memory _owners, uint256 _required) {
        require(_required > 0 && _required <= _owners.length, "Invalid threshold");
        owners = _owners;
        required = _required;
    }

    function submitTransaction(
        address payable _to,
        uint256 _value,
        bytes memory _data
    ) external returns (uint256) {
        require(msg.sender == owner(), "Only owner can submit transaction");
        proposals[proposalCount++] = Proposal({
            target: _to,
            value: _value,
            data: _data,
            executed: false
