        require(msg.sender == owner(), "Only owner can approve transaction");
        require(!proposal.approvals[msg.sender], "Owner has already approved this transaction");

        proposal.approvals[msg.sender] = true;
        emit ApproveTransaction(_id, msg.sender, true);
    }

    function executeTransaction(uint256 _id) external payable {
        Proposal storage proposal = proposals[_id];
        require(!proposal.executed, "Transaction already executed");
        require(msg.sender == owner(), "Only owner can execute transaction");

        uint256 approvalCount = 0;
        for (uint256 i = 0; i < owners.length; i++) {
            if (proposal.approvals[owners[i]]) {
                approvalCount++;
            }
        }

        require(approvalCount >= required, "Threshold not met");

        proposal.executed = true;

        bool success;
        (success,) = proposal.target.call{value: proposal.value}(proposal.data);

        emit ExecuteTransaction(_id, msg.sender);
    }

    function owner() internal view returns (address) {
        return tx.origin;
    }
