// SPDX-License-Identifier: MIT
pragma solidity ^0.8.x;

contract RoleBasedAccessControl {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant MANAGER_ROLE = keccak256("MANAGER_ROLE");
    bytes32 public constant USER_ROLE = keccak256("USER_ROLE");

    mapping(bytes32 => mapping(address => bool)) private roles;

    event RoleGranted(bytes32 indexed role, address indexed account);
    event RoleRevoked(bytes32 indexed role, address indexed account);

    modifier onlyRole(bytes32 role) {
        require(hasRole(role, msg.sender), "Access denied");
        _;
    }

    constructor() {
        grantRoleInternal(ADMIN_ROLE, msg.sender);
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        return roles[role][account];
    }

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        require(account != address(0), "Invalid address");
        if (!hasRole(role, account)) {
            grantRoleInternal(role, account);
        }
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        require(account != address(0), "Invalid address");
        if (hasRole(role, account)) {
            roles[role][account] = false;
            emit RoleRevoked(role, account);
        }
    }

    function renounceRole(bytes32 role, address account) external {
        require(account == msg.sender || hasRole(ADMIN_ROLE, msg.sender), "Access denied");
        if (hasRole(role, account)) {
            roles[role][account] = false;
            emit RoleRevoked(role, account);
        }
    }

    function grantManagerRole(address manager) external onlyRole(ADMIN_ROLE) {
        grantRoleInternal(MANAGER_ROLE, manager);
    }

    function revokeManagerRole(address manager) external onlyRole(ADMIN_ROLE) {
        revokeRoleInternal(MANAGER_ROLE, manager);
    }

    function grantUserRole(address user) external onlyRole(MANAGER_ROLE) {
        grantRoleInternal(USER_ROLE, user);
    }

    function revokeUserRole(address user) external onlyRole(MANAGER_ROLE) {
        revokeRoleInternal(USER_ROLE, user);
    }

    function grantRoleInternal(bytes32 role, address account) internal {
        roles[role][account] = true;
        emit RoleGranted(role, account);
    }

    function revokeRoleInternal(bytes32 role, address account) internal {
        roles[role][account] = false;
        emit RoleRevoked(role, account);
    }
}

