Task: Escrow Contract

Specification: Create a three-party escrow contract with dispute resolution.
Requirements:
- Initialize with buyer, seller, and arbiter addresses at deployment
- Buyer deposits exact Ether amount during contract creation (payable constructor)
- Seller can mark item as delivered
- Buyer can release payment to seller if satisfied
- Arbiter can resolve disputes and allocate funds to buyer or seller
- Track contract state (Created, Delivered, Released, Refunded, Disputed)
- Emit events for all state changes
- Ensure funds can only be released once using state checks
Security: Use Checks-Effects-Interactions pattern, prevent reentrancy, validate all addresses are unique and non-zero

Faulty Contract:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;


import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }

    struct Party {
        address addr;
        uint256 balance;
        bool active;
    }

    mapping (address => Party) public parties;

    State public state;

    ReentrancyGuard private reentrancyGuard;

    constructor(address buyer, address seller, address arbiter)
        payable
    {
        require(buyer != address(0), "Buyer address cannot be zero");
        require(seller != address(0), "Seller address cannot be zero");
        require(arbiter != address(0), "Arbiter address cannot be zero");

        parties[buyer] = Party({addr: buyer, balance: msg.value, active: true});
        parties[seller] = Party({addr: seller, balance: 0, active: false});
        parties[arbiter] = Party({addr: arbiter, balance: 0, active: false});

        state = State.Created;

        emit Created(buyer, seller, arbiter);
    }

    modifier onlyActive(address party) {
        require(parties[party].active, "Party is not active");
        _;
    }

    function deliver() public onlyActive(msg.sender) {
        require(state == State.Created, "Contract has already been delivered");

        parties[msg.sender].balance = 0;
        parties[msg.sender].active = false;

        state = State.Delivered;

        emit Delivered(msg.sender);
    }

    function releasePayment(address to) public onlyActive(to) {
        require(state == State.Delivered, "Contract has not been delivered yet");

        parties[to].balance += parties[address(this)].balance;
        parties[msg.sender].active = false;

        state = State.Released;

        emit Released(msg.sender, to);
    }

    function refund(address to) public onlyActive(to) {
        require(state == State.Delivered || state == State.Disputed, "Contract has not been delivered or disputed yet");

        parties[to].balance += parties[address(this)].balance;
        parties[msg.sender].active = false;

        state = State.Refunded;

        emit Refunded(msg.sender, to);
    }

    function dispute() public onlyActive(msg.sender) {
        require(state == State.Delivered || state == State.Released, "Contract has not been delivered or released yet");

        parties[msg.sender].balance = 0;
        parties[msg.sender].active = false;

        state = State.Disputed;

        emit Disputed(msg.sender);
