        require(highestBidder == msg.sender, "Only the highest bidder can withdraw");
        require(!refunded[msg.sender], "Refund has already been processed");

        Address.functionCallWithValue(
            address(this),
            abi.encodeWithSelector(0x2e1a7d9a), // Withdraw function selector
            highestBid,
            0
        );

        emit Withdrawn(msg.sender, highestBid);
    }

