// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract Auction {
    uint public startTime;
    uint public endTime;
    uint public minBid;

    address payable public highestBidder;
    uint public highestBid;

    bool public ended;

    mapping(address => uint) public bids;

    event NewBid(address indexed bidder, uint amount);
    event AuctionEnded(address winner, uint amount);
    event Withdrawal(address recipient, uint amount);

    constructor(uint _startTime, uint _endTime, uint _minBid) {
        require(_startTime > block.timestamp, "Start time must be in the future");
        require(_endTime > _startTime, "End time must be after start time");

        startTime = _startTime;
        endTime = _endTime;
        minBid = _minBid;
    }

    function bid() public payable {
        require(block.timestamp >= startTime, "Auction hasn't started yet");
        require(block.timestamp <= endTime, "Auction has ended");

        uint amount = msg.value;
        require(amount > minBid && amount > highestBid, "Your bid must be higher than the current highest bid and minimum bid");

        if (highestBid > 0) {
            highestBidder.transfer(highestBid);
            emit Withdrawal(highestBidder, highestBid);
        }

        bids[msg.sender] = amount;
        highestBidder = payable(msg.sender); // Cast to address payable
        highestBid = amount;

        emit NewBid(msg.sender, amount);
    }

    function withdraw() public {
        require(ended && block.timestamp > endTime + 1 weeks, "You can only withdraw after the auction has ended and it's been at least 1 week");

        uint bidAmount = bids[msg.sender];
        require(bidAmount > 0, "You didn't make a bid in this auction");

        delete bids[msg.sender];

        payable(msg.sender).transfer(bidAmount);

        emit Withdrawal(msg.sender, bidAmount);
    }

    function endAuction() public {
        require(!ended && block.timestamp > endTime, "Auction hasn't ended yet");

        ended = true;

        highestBidder.transfer(highestBid);

        emit AuctionEnded(highestBidder, highestBid);
    }
}
